ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?building ?roomnumber WHERE {
  ?courses a :Courses .
  ?courses p:Building ?building .
  ?courses p:RoomNumber ?roomnumber .
  ?courses p:CourseTitle ?coursetitle_f .
  FILTER(STR(?coursetitle_f) = STR("Human Biology"))
} }
  component: { SELECT ?roomnumber WHERE {
  ?courses a :Courses .
  ?courses p:RoomNumber ?roomnumber .
  ?courses p:CourseTitle ?coursetitle_f .
  FILTER(STR(?coursetitle_f) = STR("Human Biology"))
} }
  component_2: { SELECT ?building WHERE {
  ?courses a :Courses .
  ?courses p:Building ?building .
  ?courses p:CourseTitle ?coursetitle_f .
  FILTER(STR(?coursetitle_f) = STR("Human Biology"))
} }
}

